//! Flat C-ABI surface for the sovereign all-intra encoder, callable from a Cloudflare
//! Worker's wasm glue. Zero-dep / no `wasm-bindgen` — matches the repo's sovereign
//! `#[no_mangle] extern "C"` + bump-malloc convention so the host can pass buffers in and
//! pull the encoded MP4 back out by (ptr, len).
//!
//! Lifecycle from the host side:
//!   1. `frffmpeg_alloc(n)` → ptr; host writes the `n_frames` contiguous RGB24 frames there.
//!   2. `frffmpeg_encode_ipcm(ptr, frame_len, n_frames, w, h, fps, &out_len)` → out_ptr;
//!      `out_len` now holds the MP4 byte length, `out_ptr` points at the leaked MP4 bytes.
//!   3. host copies `out_len` bytes from `out_ptr`, then `frffmpeg_free(out_ptr, out_len)`.
//!   4. host frees the input with `frffmpeg_free(ptr, frame_len * n_frames)`.

use crate::encode_intra::{
    encode_frame_compressed_sample, encode_rgb_frames_compressed, encode_rgb_frames_ipcm,
    encode_rgb_frames_rate_controlled, encode_rgb_frames_rate_controlled_samples,
    encode_rgb_frames_rate_controlled_with_audio, encode_rgb_frames_with_audio, mux_samples,
    mux_samples_with_audio,
};

/// Allocate `len` bytes of wasm linear memory and return a pointer the host can write to.
/// Returns a null-ish dangling pointer for `len == 0`. Pair every call with `frffmpeg_free`.
#[unsafe(no_mangle)]
pub extern "C" fn frffmpeg_alloc(len: usize) -> *mut u8 {
    let mut buf: Vec<u8> = Vec::with_capacity(len);
    let ptr = buf.as_mut_ptr();
    // Leak the allocation; ownership transfers to the host until `frffmpeg_free`.
    std::mem::forget(buf);
    ptr
}

/// Free a buffer previously returned by `frffmpeg_alloc` or `frffmpeg_encode_ipcm`.
/// `len` MUST match the length the buffer was allocated/returned with.
///
/// # Safety
/// `ptr` must have come from `frffmpeg_alloc`/`frffmpeg_encode_ipcm` with the same `len`,
/// and must not be used after this call.
#[unsafe(no_mangle)]
pub unsafe extern "C" fn frffmpeg_free(ptr: *mut u8, len: usize) {
    if ptr.is_null() {
        return;
    }
    // Reconstruct the Vec with capacity == len so the global allocator frees it correctly.
    let _ = unsafe { Vec::from_raw_parts(ptr, len, len) };
}

/// Encode `n_frames` contiguous RGB24 frames (each exactly `frame_len` bytes, packed
/// `width*height*3`) into an all-intra (I_PCM) faststart MP4.
///
/// On success writes the MP4 byte length to `*out_len` and returns a pointer to the leaked
/// MP4 bytes (free it with `frffmpeg_free(ptr, *out_len)`). On bad input writes `0` to
/// `*out_len` and returns null.
///
/// # Safety
/// `frames_ptr` must point at `frame_len * n_frames` readable bytes; `out_len` must point
/// at a writable `usize`.
#[unsafe(no_mangle)]
pub unsafe extern "C" fn frffmpeg_encode_ipcm(
    frames_ptr: *const u8,
    frame_len: usize,
    n_frames: usize,
    width: u32,
    height: u32,
    fps: u32,
    out_len: *mut usize,
) -> *mut u8 {
    if out_len.is_null() {
        return core::ptr::null_mut();
    }
    if frames_ptr.is_null() || frame_len == 0 || n_frames == 0 {
        unsafe { *out_len = 0 };
        return core::ptr::null_mut();
    }

    // View the input as `n_frames` RGB24 frames. `encode_rgb_frames_ipcm` wants `&[Vec<u8>]`,
    // so copy each frame slice into an owned Vec.
    let total = frame_len.saturating_mul(n_frames);
    let all = unsafe { core::slice::from_raw_parts(frames_ptr, total) };
    let frames: Vec<Vec<u8>> = all.chunks_exact(frame_len).map(|c| c.to_vec()).collect();

    let mp4 = encode_rgb_frames_ipcm(&frames, width, height, fps);

    // Leak the MP4 Vec to the host; it owns the bytes until `frffmpeg_free`.
    let mut mp4 = mp4;
    mp4.shrink_to_fit();
    let len = mp4.len();
    let ptr = mp4.as_mut_ptr();
    std::mem::forget(mp4);
    unsafe { *out_len = len };
    ptr
}

