/// Rate-controlled video (`target_kbps`) + AAC-LC audio, muxed into ONE faststart MP4 with
/// two tracks — the audio-carrying companion to `frffmpeg_encode_rate_controlled`, mirroring
/// `frffmpeg_encode_av` but with a bitrate target instead of a fixed `qp`.
///
/// - `frames_ptr` / `frame_len` / `n_frames`: RGB24 video frames (each `width*height*3`).
/// - `width`, `height`, `fps`, `target_kbps`: video geometry / rate / **target** bitrate.
/// - `pcm_ptr` / `pcm_samples`: interleaved i16 PCM (TOTAL i16 count) — may be empty.
/// - `sample_rate`, `channels`: audio geometry.
///
/// On success writes the MP4 byte length to `*out_len` and returns a pointer to the leaked
/// MP4 bytes (free with `frffmpeg_free(ptr, *out_len)`). On bad input writes `0` to
/// `*out_len` and returns null.
///
/// # Safety
/// `frames_ptr` must point at `frame_len * n_frames` readable bytes; `pcm_ptr` must point at
/// `pcm_samples` readable `i16`s; `out_len` must point at a writable `usize`.
#[unsafe(no_mangle)]
pub unsafe extern "C" fn frffmpeg_encode_rate_controlled_av(
    frames_ptr: *const u8,
    frame_len: usize,
    n_frames: usize,
    width: u32,
    height: u32,
    fps: u32,
    target_kbps: u32,
    pcm_ptr: *const i16,
    pcm_samples: usize,
    sample_rate: u32,
    channels: u32,
    out_len: *mut usize,
) -> *mut u8 {
    if out_len.is_null() {
        return core::ptr::null_mut();
    }
    if frames_ptr.is_null() || frame_len == 0 || n_frames == 0 {
        unsafe { *out_len = 0 };
        return core::ptr::null_mut();
    }

    let total = frame_len.saturating_mul(n_frames);
    let all = unsafe { core::slice::from_raw_parts(frames_ptr, total) };
    let frames: Vec<Vec<u8>> = all.chunks_exact(frame_len).map(|c| c.to_vec()).collect();

    let pcm: Vec<i16> = if pcm_ptr.is_null() || pcm_samples == 0 {
        Vec::new()
    } else {
        unsafe { core::slice::from_raw_parts(pcm_ptr, pcm_samples) }.to_vec()
    };

    let mp4 = encode_rgb_frames_rate_controlled_with_audio(
        &frames,
        width,
        height,
        fps,
        target_kbps,
        &pcm,
        sample_rate,
        channels as u8,
    );

    let mut mp4 = mp4;
    mp4.shrink_to_fit();
    let len = mp4.len();
    let ptr = mp4.as_mut_ptr();
    std::mem::forget(mp4);
    unsafe { *out_len = len };
    ptr
}

