/// Encode ONE RGB24 frame (`frame_len` bytes, packed `width*height*3`) into a single
/// COMPRESSED AVCC sample (one length-prefixed IDR NAL). This is the fanout/shard unit:
/// a worker encodes each frame of its assigned range independently, with `idr_pic_id`
/// distinguishing the IDR. `qp` is the quantiser (0–51; ~26 default).
///
/// On success writes the sample byte length to `*out_len` and returns a pointer to the
/// leaked sample bytes (free with `frffmpeg_free(ptr, *out_len)`). On bad input writes `0`
/// to `*out_len` and returns null.
///
/// # Safety
/// `frame_ptr` must point at `frame_len` readable bytes; `out_len` must point at a writable
/// `usize`.
#[unsafe(no_mangle)]
pub unsafe extern "C" fn frffmpeg_encode_sample_compressed(
    frame_ptr: *const u8,
    frame_len: usize,
    width: u32,
    height: u32,
    qp: u32,
    idr_pic_id: u32,
    out_len: *mut usize,
) -> *mut u8 {
    if out_len.is_null() {
        return core::ptr::null_mut();
    }
    if frame_ptr.is_null() || frame_len == 0 {
        unsafe { *out_len = 0 };
        return core::ptr::null_mut();
    }

    let rgb = unsafe { core::slice::from_raw_parts(frame_ptr, frame_len) };
    let sample = encode_frame_compressed_sample(rgb, width, height, idr_pic_id, qp as u8);

    let mut sample = sample;
    sample.shrink_to_fit();
    let len = sample.len();
    let ptr = sample.as_mut_ptr();
    std::mem::forget(sample);
    unsafe { *out_len = len };
    ptr
}

/// Encode `n_frames` contiguous RGB24 frames (each `frame_len` bytes, packed `width*height*3`)
/// into rate-controlled COMPRESSED AVCC samples (one independent IDR per frame, in playback
/// order) — the SHARDED-fold input whose per-frame QP adapts to hit `target_kbps` (target
/// **video** bitrate in kbit/s). This is the rate-controlled companion to
/// `frffmpeg_encode_sample_compressed` (which encodes a single frame at a fixed `qp`): the
/// controller is a sequential per-frame feedback loop, so all of a shard's frames are encoded
/// in ONE call, and the controller seeds from the target and adapts across the shard's own
/// frames (a shard = a contiguous frame range).
///
/// Output convention mirrors `frffmpeg_mux_samples`' length-table, in the OUTPUT direction:
/// the host pre-allocates `lens_ptr` as `n_frames` writable u32 slots; on success this writes
/// each frame's sample byte length there (in frame order) and returns a pointer to the
/// `sum(lens)`-byte concatenation of the samples (free with `frffmpeg_free(ptr, sum(lens))`).
/// On bad input writes `0` to `*out_len` and returns null.
///
/// # Safety
/// `frames_ptr` must point at `frame_len * n_frames` readable bytes; `lens_ptr` must point at
/// `n_frames` writable `u32`s; `out_len` must point at a writable `usize`.
#[unsafe(no_mangle)]
pub unsafe extern "C" fn frffmpeg_encode_rate_controlled_samples(
    frames_ptr: *const u8,
    frame_len: usize,
    n_frames: usize,
    width: u32,
    height: u32,
    fps: u32,
    target_kbps: u32,
    lens_ptr: *mut u32,
    out_len: *mut usize,
) -> *mut u8 {
    if out_len.is_null() {
        return core::ptr::null_mut();
    }
    if frames_ptr.is_null() || lens_ptr.is_null() || frame_len == 0 || n_frames == 0 {
        unsafe { *out_len = 0 };
        return core::ptr::null_mut();
    }

    let total = frame_len.saturating_mul(n_frames);
    let all = unsafe { core::slice::from_raw_parts(frames_ptr, total) };
    let frames: Vec<Vec<u8>> = all.chunks_exact(frame_len).map(|c| c.to_vec()).collect();

    let samples =
        encode_rgb_frames_rate_controlled_samples(&frames, width, height, fps, target_kbps);

    // Write the per-frame sample lengths into the host's lens table (frame order).
    let lens = unsafe { core::slice::from_raw_parts_mut(lens_ptr, n_frames) };
    for (i, s) in samples.iter().enumerate() {
        if i < n_frames {
            lens[i] = s.len() as u32;
        }
    }

    // Concatenate the samples into one leaked blob; the host slices it apart via `lens`.
    let mut blob: Vec<u8> = Vec::with_capacity(samples.iter().map(|s| s.len()).sum());
    for s in &samples {
        blob.extend_from_slice(s);
    }
    blob.shrink_to_fit();
    let len = blob.len();
    let ptr = blob.as_mut_ptr();
    std::mem::forget(blob);
    unsafe { *out_len = len };
    ptr
}

/// Mux pre-encoded shard samples (the fold step) into a faststart MP4. `samples_ptr` is the
/// concatenation of all `n_samples` AVCC samples; `lens_ptr` is an array of `n_samples` u32
/// lengths giving each sample's byte length (in frame order). The samples are sliced back
/// apart and muxed via `encode_intra::mux_samples`.
///
/// On success writes the MP4 byte length to `*out_len` and returns a pointer to the leaked
/// MP4 bytes (free with `frffmpeg_free(ptr, *out_len)`). On bad input writes `0` to
/// `*out_len` and returns null.
///
/// # Safety
/// `samples_ptr` must point at `sum(lens)` readable bytes; `lens_ptr` must point at
/// `n_samples` readable `u32`s; `out_len` must point at a writable `usize`.
#[unsafe(no_mangle)]
pub unsafe extern "C" fn frffmpeg_mux_samples(
    samples_ptr: *const u8,
    lens_ptr: *const u32,
    n_samples: usize,
    width: u32,
    height: u32,
    fps: u32,
    out_len: *mut usize,
) -> *mut u8 {
    if out_len.is_null() {
        return core::ptr::null_mut();
    }
    if samples_ptr.is_null() || lens_ptr.is_null() || n_samples == 0 {
        unsafe { *out_len = 0 };
        return core::ptr::null_mut();
    }

    // Read the per-sample lengths and slice the concatenated blob back into owned Vecs.
    let lens = unsafe { core::slice::from_raw_parts(lens_ptr, n_samples) };
    let total: usize = lens.iter().map(|&l| l as usize).sum();
    let all = unsafe { core::slice::from_raw_parts(samples_ptr, total) };
    let mut samples: Vec<Vec<u8>> = Vec::with_capacity(n_samples);
    let mut off = 0usize;
    for &l in lens {
        let l = l as usize;
        samples.push(all[off..off + l].to_vec());
        off += l;
    }

    let mp4 = mux_samples(&samples, width, height, fps);

    let mut mp4 = mp4;
    mp4.shrink_to_fit();
    let len = mp4.len();
    let ptr = mp4.as_mut_ptr();
    std::mem::forget(mp4);
    unsafe { *out_len = len };
    ptr
}

/// Mux pre-encoded shard video samples (the fold step) TOGETHER with an AAC-LC audio track
/// into a faststart MP4 with TWO tracks. This is the audio-carrying fold: the SHARDED
/// (fanout) full-length clip path produces only video samples, so this adds sound to them.
///
/// `samples_ptr` is the concatenation of all `n_samples` AVCC samples; `lens_ptr` is an
/// array of `n_samples` u32 lengths giving each sample's byte length (in frame order). The
/// samples are sliced back apart, paired with the i16 PCM, and muxed via
/// `encode_intra::mux_samples_with_audio`.
///
/// - `samples_ptr` / `lens_ptr` / `n_samples`: the AVCC video samples (the fold input).
/// - `width`, `height`, `fps`: video geometry / rate.
/// - `pcm_ptr`: pointer to `pcm_samples` interleaved i16 samples (mono or stereo).
/// - `pcm_samples`: TOTAL i16 count (samples_per_channel * channels).
/// - `sample_rate`, `channels`: audio geometry.
///
/// On success writes the MP4 byte length to `*out_len` and returns a pointer to the leaked
/// MP4 bytes (free with `frffmpeg_free(ptr, *out_len)`). On bad input writes `0` to
