///
/// # Safety
/// `samples_ptr` must point at `sum(lens)` readable bytes; `lens_ptr` must point at
/// `n_samples` readable `u32`s; `pcm_ptr` must point at `pcm_samples` readable `i16`s;
/// `out_len` must point at a writable `usize`.
#[unsafe(no_mangle)]
pub unsafe extern "C" fn frffmpeg_mux_samples_av(
    samples_ptr: *const u8,
    lens_ptr: *const u32,
    n_samples: usize,
    width: u32,
    height: u32,
    fps: u32,
    pcm_ptr: *const i16,
    pcm_samples: usize,
    sample_rate: u32,
    channels: u8,
    out_len: *mut usize,
) -> *mut u8 {
    if out_len.is_null() {
        return core::ptr::null_mut();
    }
    if samples_ptr.is_null() || lens_ptr.is_null() || n_samples == 0 {
        unsafe { *out_len = 0 };
        return core::ptr::null_mut();
    }

    // Read the per-sample lengths and slice the concatenated blob back into owned Vecs.
    let lens = unsafe { core::slice::from_raw_parts(lens_ptr, n_samples) };
    let total: usize = lens.iter().map(|&l| l as usize).sum();
    let all = unsafe { core::slice::from_raw_parts(samples_ptr, total) };
    let mut samples: Vec<Vec<u8>> = Vec::with_capacity(n_samples);
    let mut off = 0usize;
    for &l in lens {
        let l = l as usize;
        samples.push(all[off..off + l].to_vec());
        off += l;
    }

    // PCM may be empty (audio-less); guard the null+len combination.
    let pcm: Vec<i16> = if pcm_ptr.is_null() || pcm_samples == 0 {
        Vec::new()
    } else {
        unsafe { core::slice::from_raw_parts(pcm_ptr, pcm_samples) }.to_vec()
    };

    let mp4 = mux_samples_with_audio(&samples, width, height, fps, &pcm, sample_rate, channels);

    let mut mp4 = mp4;
    mp4.shrink_to_fit();
    let len = mp4.len();
    let ptr = mp4.as_mut_ptr();
    std::mem::forget(mp4);
    unsafe { *out_len = len };
    ptr
}

/// Encode packed RGB24 frames straight to an FLV stream — the sovereign `-f flv`.
/// `frames_ptr` is `n_frames` × `frame_len` (= width*height*3) of packed RGB24.
/// Drives encode_gop (IDR + P-skip) → FLV. On success writes the FLV byte length to
/// `*out_len` and returns a pointer to the leaked bytes (free with `frffmpeg_free`).
///
/// # Safety
/// `frames_ptr` must point at `n_frames*frame_len` readable bytes; `out_len` must
/// point at a writable `usize`.
#[unsafe(no_mangle)]
pub unsafe extern "C" fn frffmpeg_encode_rgb_flv(
    frames_ptr: *const u8,
    frame_len: usize,
    n_frames: usize,
    width: u32,
    height: u32,
    fps: u32,
    qp: u32,
    out_len: *mut usize,
) -> *mut u8 {
    if out_len.is_null() {
        return core::ptr::null_mut();
    }
    if frames_ptr.is_null() || n_frames == 0 {
        unsafe { *out_len = 0 };
        return core::ptr::null_mut();
    }
    let total = frame_len.saturating_mul(n_frames);
    let all = unsafe { core::slice::from_raw_parts(frames_ptr, total) };
    let frames: Vec<Vec<u8>> = all.chunks_exact(frame_len).map(|c| c.to_vec()).collect();
    let flv = crate::encode_intra::encode_rgb_frames_flv(&frames, width, height, fps, qp as u8);
    let mut flv = flv;
    flv.shrink_to_fit();
    let len = flv.len();
    let ptr = flv.as_mut_ptr();
    std::mem::forget(flv);
    unsafe { *out_len = len };
    ptr
}

/// Encode packed RGB24 frames + an AAC-LC audio track straight to an FLV stream that
/// carries BOTH video (tag 0x09) AND audio (tag 0x08) — the sovereign `-f flv` WITH sound.
/// Mirrors [`frffmpeg_encode_rgb_flv`] with the PCM audio args appended; drives
/// `encode_intra::encode_rgb_frames_av_flv`.
///
/// - `frames_ptr` / `frame_len` / `n_frames`: RGB24 video frames (each `width*height*3`).
/// - `width`, `height`, `fps`, `qp`: video geometry / rate / quantiser.
/// - `pcm_ptr`: pointer to `pcm_samples` interleaved i16 samples (mono or stereo) — may be null.
/// - `pcm_samples`: TOTAL i16 count (samples_per_channel * channels); 0 ⇒ no audio.
/// - `sample_rate`, `channels`: audio geometry (e.g. 44100, 1).
///
/// On success writes the FLV byte length to `*out_len` and returns a pointer to the leaked
/// bytes (free with `frffmpeg_free(ptr, *out_len)`); on bad input writes `0` and returns null.
///
/// # Safety
/// `frames_ptr` must point at `n_frames*frame_len` readable bytes; `pcm_ptr` must point at
/// `pcm_samples` readable `i16`s; `out_len` must point at a writable `usize`.
#[unsafe(no_mangle)]
#[allow(clippy::too_many_arguments)]
pub unsafe extern "C" fn frffmpeg_encode_rgb_av_flv(
    frames_ptr: *const u8,
    frame_len: usize,
    n_frames: usize,
    width: u32,
    height: u32,
    fps: u32,
    qp: u32,
    pcm_ptr: *const i16,
    pcm_samples: usize,
    sample_rate: u32,
    channels: u32,
    out_len: *mut usize,
) -> *mut u8 {
    if out_len.is_null() {
        return core::ptr::null_mut();
    }
    if frames_ptr.is_null() || n_frames == 0 {
        unsafe { *out_len = 0 };
        return core::ptr::null_mut();
    }
    let total = frame_len.saturating_mul(n_frames);
    let all = unsafe { core::slice::from_raw_parts(frames_ptr, total) };
    let frames: Vec<Vec<u8>> = all.chunks_exact(frame_len).map(|c| c.to_vec()).collect();

    // PCM may be empty (audio-less); guard the null+len combination.
    let pcm: Vec<i16> = if pcm_ptr.is_null() || pcm_samples == 0 {
        Vec::new()
    } else {
        unsafe { core::slice::from_raw_parts(pcm_ptr, pcm_samples) }.to_vec()
    };

    let flv = crate::encode_intra::encode_rgb_frames_av_flv(
        &frames,
        width,
        height,
        fps,
        qp as u8,
        &pcm,
        sample_rate,
        channels as u8,
    );
    let mut flv = flv;
    flv.shrink_to_fit();
    let len = flv.len();
    let ptr = flv.as_mut_ptr();
    std::mem::forget(flv);
    unsafe { *out_len = len };
    ptr
}

/// Mux PRE-ENCODED H.264 (AVC) + AAC into an FLV stream (the RTMP container).
///
/// Unlike the MP4 exports, the codecs are already done: pass the SPS/PPS, the AVCC
/// video samples (concatenated, with `vlens` byte lengths), the AudioSpecificConfig,
/// and the raw AAC frames (concatenated, with `alens` lengths). Calls
/// [`crate::flv::mux_av_flv`]. On success writes the FLV byte length to `*out_len`
/// and returns a pointer to the leaked bytes (free with `frffmpeg_free`); on bad
/// input writes `0` and returns null.
///
/// # Safety
/// Each `*_ptr` must point at the stated number of readable bytes; `vlens_ptr`/
/// `alens_ptr` must point at `n_vsamples`/`n_aframes` readable `u32`s; `out_len`
/// must point at a writable `usize`.
#[unsafe(no_mangle)]
#[allow(clippy::too_many_arguments)]
pub unsafe extern "C" fn frffmpeg_mux_av_flv(
    sps_ptr: *const u8,
    sps_len: usize,
    pps_ptr: *const u8,
    pps_len: usize,
    vsamples_ptr: *const u8,
    vlens_ptr: *const u32,
    n_vsamples: usize,
    width: u32,
    height: u32,
    fps: u32,
    asc_ptr: *const u8,
    asc_len: usize,
    aframes_ptr: *const u8,
    alens_ptr: *const u32,
    n_aframes: usize,
    sample_rate: u32,
    channels: u8,
    out_len: *mut usize,
) -> *mut u8 {
    if out_len.is_null() {
        return core::ptr::null_mut();
    }
    if sps_ptr.is_null() || pps_ptr.is_null() || vsamples_ptr.is_null() || vlens_ptr.is_null() {
        unsafe { *out_len = 0 };
        return core::ptr::null_mut();
    }

    // Slice a concatenated blob back into owned Vecs using its per-item lengths.
    fn slice_blobs(blob_ptr: *const u8, lens_ptr: *const u32, n: usize) -> Vec<Vec<u8>> {
        if blob_ptr.is_null() || lens_ptr.is_null() || n == 0 {
            return Vec::new();
        }
        let lens = unsafe { core::slice::from_raw_parts(lens_ptr, n) };
        let total: usize = lens.iter().map(|&l| l as usize).sum();
        let all = unsafe { core::slice::from_raw_parts(blob_ptr, total) };
        let mut out = Vec::with_capacity(n);
        let mut off = 0usize;
        for &l in lens {
            let l = l as usize;
            out.push(all[off..off + l].to_vec());
            off += l;
        }
        out
    }

    let sps = unsafe { core::slice::from_raw_parts(sps_ptr, sps_len) };
    let pps = unsafe { core::slice::from_raw_parts(pps_ptr, pps_len) };
    let asc: &[u8] = if asc_ptr.is_null() || asc_len == 0 {
        &[]
    } else {
        unsafe { core::slice::from_raw_parts(asc_ptr, asc_len) }
    };
    let video = slice_blobs(vsamples_ptr, vlens_ptr, n_vsamples);
    let audio = slice_blobs(aframes_ptr, alens_ptr, n_aframes);

    let flv = crate::flv::mux_av_flv(
        sps, pps, &video, width, height, fps, asc, &audio, sample_rate, channels,
    );

    let mut flv = flv;
    flv.shrink_to_fit();
    let len = flv.len();
    let ptr = flv.as_mut_ptr();
    std::mem::forget(flv);
    unsafe { *out_len = len };
    ptr
}
